sparql:
SELECT ?aestheticName ?locationLabel ?platformLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName .
  OPTIONAL {
    ?aesthetic ae-ont:hasLocationOfOrigin ?location .
    ?location rdfs:label ?locationLabel .
  }
  OPTIONAL {
    ?aesthetic ae-ont:hasPrimaryPlatform ?platform .
    ?platform rdfs:label ?platformLabel .
  }
  FILTER(str(?aestheticName) = "Cottagecore")
}

SELECT ?aestheticName ?periodLabel ?startYear
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasOriginPeriod ?period .
  ?period ae-ont:approximateLabel ?periodLabel ;
          ae-ont:startYear ?startYear .
  FILTER(str(?startYear) >= "2000")
}
ORDER BY ?startYear
LIMIT 30

SELECT ?workTitle ?workType
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasRelatedWork ?work .
  ?work a ?workType ;
        rdfs:label ?workTitle .
  FILTER(str(?aestheticName) = "Dark Academia")
  FILTER(?workType != owl:NamedIndividual)
}
ORDER BY ?workType ?workTitle

SELECT ?aestheticName (COUNT(?work) AS ?filmCount)
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasRelatedWork ?work .
  ?work a ae-ont:Film .
}
GROUP BY ?aestheticName
ORDER BY DESC(?filmCount)
LIMIT 20

SELECT ?aestheticName ?locationLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasLocationOfOrigin ?location .
  ?location rdfs:label ?locationLabel .
  FILTER(CONTAINS(LCASE(str(?locationLabel)), "japan"))
}
ORDER BY ?aestheticName

SELECT ?aestheticName ?figureName
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasIconicFigure ?figure .
  ?figure rdfs:label ?figureName .
  FILTER(str(?aestheticName) = "Dark Cabaret")
}
ORDER BY ?figureName

SELECT ?brandLabel ?valueLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName .
  OPTIONAL {
    ?aesthetic ae-ont:hasRelatedBrand ?brand .
    ?brand rdfs:label ?brandLabel .
  }
  OPTIONAL {
    ?aesthetic ae-ont:hasMember ?value .
    ?value a ae-ont:Value ;
           rdfs:label ?valueLabel .
  }
  FILTER(str(?aestheticName) = "Normcore")
}

SELECT ?aestheticName
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasMember ?color .
  ?color a ae-ont:Color ;
         rdfs:label "black"@en .
}
ORDER BY ?aestheticName
LIMIT 30

SELECT ?motifLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasMember ?motif .
  ?motif a ae-ont:Motif ;
         rdfs:label ?motifLabel .
  FILTER(str(?aestheticName) = "Gothic")
}
ORDER BY ?motifLabel

SELECT ?brandLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasRelatedBrand ?brand .
  ?brand rdfs:label ?brandLabel .
  FILTER(str(?aestheticName) = "Preppy")
}
ORDER BY ?brandLabel

SELECT ?relatedName ?relationType
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName .
  FILTER(str(?aestheticName) = "Cottagecore")
  {
    ?aesthetic ae-ont:relatedTo ?related .
    BIND("relatedTo" AS ?relationType)
  } UNION {
    ?aesthetic ae-ont:overlapsWith ?related .
    BIND("overlapsWith" AS ?relationType)
  } UNION {
    ?aesthetic ae-ont:hasSubgenre ?related .
    BIND("hasSubgenre" AS ?relationType)
  }
  ?related ae-ont:name ?relatedName .
}
ORDER BY ?relationType ?relatedName

SELECT ?subgenreName
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasSubgenre ?sub .
  ?sub ae-ont:name ?subgenreName .
  FILTER(str(?aestheticName) = "Punk")
}
ORDER BY ?subgenreName

SELECT ?influencerName
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?n .
  FILTER(str(?n) = "DIY Punk")
  ?aesthetic ae-ont:follows ?influencer .
  ?influencer ae-ont:name ?influencerName .
}

SELECT DISTINCT ?relatedName ?relationType
WHERE {
  ?source a ae-ont:Aesthetic ;
          ae-ont:name ?sourceName .
  FILTER(str(?sourceName) = "Memphis Lite")
  {
    ?source ae-ont:hasSubgenre ?related .
    BIND("subgenre" AS ?relationType)
  } UNION {
    ?source ae-ont:follows ?related .
    BIND("follows" AS ?relationType)
  } UNION {
    ?source ae-ont:overlapsWith ?related .
    BIND("overlapsWith" AS ?relationType)
  } UNION {
    ?source ae-ont:hasMember ?v .
    ?v a ae-ont:Value .
    ?related ae-ont:hasMember ?v .
    ?related a ae-ont:Aesthetic .
    FILTER(?related != ?source)
    BIND("sharedValue" AS ?relationType)
  }
  ?related ae-ont:name ?relatedName .
}
ORDER BY ?relationType

SELECT ?aestheticName (COUNT(?sub) AS ?subCount)
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasSubgenre ?sub .
}
GROUP BY ?aestheticName
ORDER BY DESC(?subCount)
LIMIT 20

SELECT ?aestheticName (COUNT(DISTINCT ?descendant) AS ?chainLength)
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName .
  ?aesthetic ae-ont:precedes+ ?descendant .
}
GROUP BY ?aestheticName
ORDER BY DESC(?chainLength)
LIMIT 10

SELECT DISTINCT ?aestheticName ?motifLabel
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasMember ?motif .
  ?motif a ae-ont:Motif ;
         rdfs:label ?motifLabel .
  FILTER(
    CONTAINS(LCASE(str(?motifLabel)), "dress")  ||
    CONTAINS(LCASE(str(?motifLabel)), "clothing") ||
    CONTAINS(LCASE(str(?motifLabel)), "outfit")  ||
    CONTAINS(LCASE(str(?motifLabel)), "jacket")  ||
    CONTAINS(LCASE(str(?motifLabel)), "boots")   ||
    CONTAINS(LCASE(str(?motifLabel)), "skirt")   ||
    CONTAINS(LCASE(str(?motifLabel)), "jeans")
  )
}
ORDER BY ?aestheticName
LIMIT 40

SELECT ?aestheticName (COUNT(DISTINCT ?brand) AS ?brandCount)
WHERE {
  ?aesthetic a ae-ont:Aesthetic ;
             ae-ont:name ?aestheticName ;
             ae-ont:hasRelatedBrand ?brand .
}
GROUP BY ?aestheticName
ORDER BY DESC(?brandCount)
LIMIT 20
